var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"제길, 이 자식 더럽게 끈질기네……!","JPN":"くっそ、しつこいな……！","ENG":"Damn it! He just won't quit...!","TWN":"可惡，這傢伙真是頑固……！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"탄창은 이게 마지막인가?","JPN":"弾倉はこれが最後か？","ENG":"Is this... the last magazine?","TWN":"彈匣是最後一個了嗎？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L9_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"소용없다. 녹색 머리 여자.","JPN":"無駄ダ。緑ノ髪ノ女。","ENG":"It's useless. Green-haired woman.","TWN":"沒用的，綠色頭髮的女人。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_15"},{"id":"L10_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"우리는 너희를 모방하고. 학습하며. 진화한다.","JPN":"オレタチハオマエラヲ模倣シ、学習シ、進化スル。","ENG":"We imitate. We learn. We evolve.","TWN":"我們模仿你們，學習你們，進化。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"그리고 결국 너희를 포식하지.","JPN":"ソシテ最後ニハオマエラヲ捕食スル。","ENG":"And in the end, we devour you.","TWN":"最後還是會吞噬你們。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"얌전히 내게 먹혀라. 녹색 머리 여자.","JPN":"大人シクオレニ食ワレロ。緑ノ髪ノ女。","ENG":"Let me eat you. Green-haired woman.","TWN":"乖乖地被我吃掉吧，綠發女人。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_02"},{"id":"L14_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"먹혀서 그것의 정보를 내놔라.","JPN":"食ワレテ、アレノ情報ヲヨコセ。","ENG":"Be consumed. Offer up what you know.","TWN":"被吞噬了，把它的資訊交出來。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"그리운 근원. 모든 것의 고향.","JPN":"懐カシイ根源。全テノ故郷。","ENG":"The origin. Home of everything.","TWN":"懷念的根源，一切的故鄉。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"세계를 만드는 법칙. 그 나무로부터 내려온 존재.","JPN":"世界ヲ作ル法則。カノ木ヨリ送ラレタ存在。","ENG":"The law of creating a world. The one, descended from the tree.","TWN":"創造世界的規則。從那棵樹上降臨的存在。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"작은 여자가 있는 곳. 넘겨라.","JPN":"小サイ女ノ居場所。ヨコセ。","ENG":"The location where the small girl is. Hand over the info.","TWN":"有小女孩的地方，交出來。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"아까부터 무슨 헛소리를 하는 거야!","JPN":"さっきから何言ってんだよ！","ENG":"What nonsense are you even spouting?!","TWN":"從剛才開始，你到底在胡說八道什麼！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L21_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"누굴 찾는지는 몰라도 번지수 잘못 찾았다니까! 내 고향 녀석들은 전부 뒈진 지 오래라고!","JPN":"誰を探してるのか知らないけど、お門違いだって！　私の故郷のやつらは全員死んだんだ！","ENG":"I don't know who you're looking for, but you're asking the wrong person! Everyone from my hometown has been dead for ages!","TWN":"不知道你在找誰，但你找錯地方了！我家鄉的人早就全死光了！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"큭. 큭. 큭. 큭.","JPN":"クッ。クッ。クッ。クッ。","ENG":"Ke. Ke. Ke. Ke.","TWN":"咳，咳，咳。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_19"},{"id":"L25_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"총. 인간의 무기. 여러 번 동포를 죽였지.","JPN":"銃。人間ノ武器。何回モ仲間ヲ殺シタ。","ENG":"Guns. Human weapons. They killed many of my kind.","TWN":"槍。人類的武器。曾多次殺害同胞。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"하지만. 이 정도 위력으로는 나를 죽일 수 없다.","JPN":"シカシ、コノ程度デハ、オレヲ殺セナイ。","ENG":"But. This level of firepower can't kill me.","TWN":"但是，憑這種程度的威力是無法殺死我的。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"잠깐……?","JPN":"おいおい……","ENG":"What...?","TWN":"等一下……?"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"저 녀석, 팔의 형태가……!?","JPN":"あいつ、腕の形態が……！？","ENG":"His arm... it's morphing...?!","TWN":"那傢伙，手臂的形態是……？！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"받아라. 인간.","JPN":"ココマデダ、人間。","ENG":"Take this. Human.","TWN":"嚐嚐吧！人類。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"라이카! 괜찮아요?","JPN":"ライカ！　大丈夫？","ENG":"Laika! Are you okay?","TWN":"萊卡！你沒事吧？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"꼬맹이, 네가 안 막아줬으면 골로 갈 뻔했다. 야.","JPN":"ふう。おかげで助かったよ、おこちゃま。","ENG":"If you hadn't blocked that, kid... I'd be toast.","TWN":"小鬼，要不是你擋住了，我差點就完蛋了。嘿。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L39_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그보다 방금 봤어? 저 녀석, 방금 카운터 능력 같은 걸 썼다고!","JPN":"それより、今の見た？　あいつ、カウンター能力みたいなやつを使いやがった！","ENG":"Did you see that just now? He just used some kind of ability like that of a Counter!","TWN":"比起這個，你剛才看到了嗎？那傢伙剛才好像使用了制裁者的能力！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L40_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"아까도 느꼈지만, 지난 번에 봤을 때보다 훨씬 강해진 것 같아.","JPN":"さっきも思ったけど、前に見た時よりずっと強くなってる気がする。","ENG":"I felt it earlier too, but he's way stronger than the last time we saw him.","TWN":"剛才也感覺到了，好像比上次見到的時候更強了。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L41_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"맞아요. 왠지 말투도 달라진 것 같아요.","JPN":"そうね。なんだか喋り方も変わってるみたい。","ENG":"Yeah. Even the way he talks feels different.","TWN":"沒錯，感覺說話的語氣也變了。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L44_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"그 방패. 확실히 성가시군.","JPN":"ソノ盾。厄介ダナ。","ENG":"That shield. It's a problem.","TWN":"那個盾牌，確實很煩人。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"지금까지. 본 적 없는 물건이다.","JPN":"今マデ、見タコトナイモノ。","ENG":"I've never seen. Anything like that before.","TWN":"至今為止，從未見過的物品。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"노란 머리 여자. 녀석의 방패를 가져와라.","JPN":"黄色イ髪ノ女。ヤツノ盾ヲ持ッテ来イ。","ENG":"Blond-haired girl. Bring me the shield.","TWN":"金髮女人，把她的盾牌拿過來。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"제길, 또 침식 쐐기를 꺼내서 숫자로 밀어붙일 속셈이야!","JPN":"くそ、また侵食楔を出して物量作戦に出る気だ！","ENG":"Damn it, he's pulling out a Corrupted Wedge again to overwhelm us with numbers!","TWN":"該死，他們又拿出了侵蝕釘，打算用人數優勢壓制我們！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L1_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"흥! 그렇게 놔둘 줄 알고……!","JPN":"ふん！　させないわ……！","ENG":"Tch! You think I'm just gonna let that happen...?!","TWN":"哼！你以為我會就這麼放過你……！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L2_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"라이카, 인적이 드문 여기라면, 피해를 최소화할 수 있어요……!","JPN":"ライカ、人気のないここなら被害を最小限に抑えることができる……！","ENG":"Laika, there aren't many people around here. We can minimize collateral damage...!","TWN":"萊卡，這裡人跡罕至，可以將傷害降到最低……！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L3_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"좋아, 시간은 내가 벌어줄게.","JPN":"よし、私が時間を稼ぐ。","ENG":"All right, I'll buy us some time.","TWN":"好，我來爭取時間。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L4_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"날려 버려! 꼬맹이!","JPN":"ぶっ飛ばせ、おこちゃま！","ENG":"Do it, kid! Blast 'em!","TWN":"做掉你！小鬼！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"좌표 고정!","JPN":"座標固定！","ENG":"Coordinates locked!","TWN":"固定座標！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"처음보는 무기. 위험하군.","JPN":"初メテ見ル武器。危険ダ。","ENG":"That weapon. Never seen before. It's dangerous.","TWN":"第一次見到的武器，很危險。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"노란 머리 여자. 녀석을 막아라.","JPN":"黄色イ髪ノ女。ヤツヲ止メロ。","ENG":"Blond-haired girl. Stop her.","TWN":"金髮女人，攔住她。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_46"},{"id":"L14_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"어이 형씨! 눈깔이 없어서, 어디 뵈는 게 없나 봐?","JPN":"おい、そこのお兄さん！　目がなくて何も見えないのか？","ENG":"Hey! You blind ‘cause you got no eyes, or just plain dumb?","TWN":"喂，大哥！你是沒長眼睛嗎，看不見路嗎？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L15_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"내가 꼬맹이한테 접근하게 내버려 둘 것 같아?","JPN":"私がおこちゃまに近づかせると思う？","ENG":"You really think I'm gonna let you anywhere near the kid?","TWN":"你以為我會讓你接近那個小鬼嗎？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"거기서 얌전히 벼락이나 맞고 뒈져버리라고, 이 망할 침식체……!","JPN":"大人しく雷にでも打たれてくたばるんだな、くそ侵食体が……！","ENG":"Just stand there and get struck by lightning, you damn C.O.!","TWN":"在那裡乖乖地被雷劈死吧，該死的侵蝕體……！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L20_1","type":"dialog","speaker":"ROSE_BETA_MAID_ON","text":{"KOREA":"여기는 BR-27. 포인트에서 대기 중.","JPN":"こちらBR-27。ポイントで待機中。","ENG":"This is BR-27. Standing by at the point.","TWN":"這裡是BR-27，在指定地點待命。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_ON","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L21_1","type":"dialog","speaker":"ROSE_BETA_MAID_ON","text":{"KOREA":"현재 위치에서 언제든지 목표 저격이 가능합니다.","JPN":"現地点からいつでもターゲットを狙撃可能です。","ENG":"The target is within sniping range.","TWN":"目前位置，可隨時進行目標狙擊。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROSE_BETA_MAID_ON","text":{"KOREA":"마스터, 지시를.","JPN":"マスター、ご指示を。","ENG":"Awaiting orders, Master.","TWN":"主人，請下達指示。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROSE_BETA_MAID_ON","text":{"KOREA":"……수신.","JPN":"……了解。","ENG":"...Copy that.","TWN":"……收到。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROSE_BETA_MAID_ON","text":{"KOREA":"목표를 제압하겠습니다.","JPN":"ターゲットを制圧します。","ENG":"Target will be neutralized.","TWN":"我要制伏目標。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"아얏……!","JPN":"いたっ……！","ENG":"Ouch...!","TWN":"啊呀……！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"뭐야!? 저격인가? 어디서……!?","JPN":"なんだ！？　狙撃か？　どこから……！？","ENG":"W-what the?! Is it a sniper?! But where…?!","TWN":"怎麼回事？！是狙擊嗎？從哪裡……？！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"젠장! 야, 꼬맹이 괜찮아……!?","JPN":"くそ！　おい、おこちゃま！　大丈夫か……！？","ENG":"Damn it! Hey, kid, are you okay...?!","TWN":"可惡！喂，小鬼你沒事吧……！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"전 괜찮아요! 살짝 스쳤을 뿐이니까……!","JPN":"私は大丈夫！　かすっただけだから……！","ENG":"Yeah! Just a scratch... I'm okay!","TWN":"我沒事！只是擦傷而已……！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그보다 앞을 봐요! 정면에 침식체가……!","JPN":"それより前を見て！　正面に侵食体が……！","ENG":"But look ahead! There's a C.O. right in front of us...!","TWN":"先不說了，快看前面！正前方有侵蝕體……！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"젠장, 나도 알고 있다고!","JPN":"ちくしょう、わかってるよ！","ENG":"I know, damn it! I see it too!","TWN":"該死，我也知道！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"큭큭큭.","JPN":"クックックッ。","ENG":"Kekeke.","TWN":"吭吭吭。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L40_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"끝이다. 인간.","JPN":"終ワリダ、人間。","ENG":"It's over, human.","TWN":"結束了，人類。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"크윽. 크하아아아아악……!!","JPN":"クウッ、クアアアアア……！！","ENG":"Argh. Aaah...!","TWN":"咳。呃啊啊啊啊啊……！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_45"},{"id":"L45_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"봤어요, 라이카?","JPN":"見た、ライカ？","ENG":"Did you see that, Laika?","TWN":"看到了嗎，萊卡？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L46_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"침식체가… 순식간에 먼지처럼 사라져 버렸어요…….","JPN":"侵食体が……あっという間に灰になって消えちゃった……","ENG":"The C.O. just disintegrated into dust, all at once...","TWN":"侵蝕體……瞬間就像灰塵一樣消失了……"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"나도 봤어. 하지만…….","JPN":"見たよ。それにしても……","ENG":"Yeah, I saw it too. But still...","TWN":"我也看到了。但是……"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"저 녀석을 고작 총알 몇 발에 가루로 만들어버릴 정도의 위력이라고……?","JPN":"あいつをたった数発で粉々にするほどの威力だと……？","ENG":"That kind of firepower... from just a few bullets?","TWN":"那傢伙竟然能被幾顆子彈打成粉末……？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"설마, 아까 그 저격인가?","JPN":"まさか、さっきの狙撃か？","ENG":"Wait... was that the same sniper from earlier?","TWN":"難道，是剛才的那次狙擊嗎？"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L1_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"아니야… 총알이 날아오는 소리가 달랐어. 그건 발사 위치가 다르다는 뜻…….","JPN":"いや……銃弾が飛ぶ音が違ってた。つまり発射元が違う……","ENG":"No... the sound of the bullet was different. That means the shot came from a different position.","TWN":"不對……子彈飛來的聲音不一樣。這意味著發射位置不同……"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그렇다는 말은 매복하고 있는 녀석은 최소한 둘 이상.","JPN":"ということは、待ち伏せしているやつは少なくとも2人以上。","ENG":"Which means... there are at least two people lying in ambush.","TWN":"也就是說，埋伏的傢伙至少有兩個以上。"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"누구지…? 역시 가장 가능성이 높은 건 북방합의체 녀석들인가……?","JPN":"誰だ……？　やっぱり可能性が一番高いのは、北方合意体のやつらか……？","ENG":"Who are they...? Would it be the Northern Union…?","TWN":"是誰呢……？果然最有可能的是北方和議會那幫傢伙嗎……？"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그게 아니라면…….","JPN":"それとも……","ENG":"But if not them, then...","TWN":"或者說……"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ROSE_BETA_MAID_QM","text":{"KOREA":"여기는 BR-19. 명령대로 목표 대상을 제거하였습니다.","JPN":"こちらBR-19。命令通りターゲットを排除しました。","ENG":"This is BR-19. Target eliminated as ordered.","TWN":"這裡是BR-19，已按照命令消滅目標。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L7_1","type":"dialog","speaker":"ROSE_BETA_MAID_QM","text":{"KOREA":"마스터, 다음 지시를.","JPN":"マスター、次のご指示を。","ENG":"Awaiting the next order, Master.","TWN":"主人，請下達下一步指示。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"어, 어어……?","JPN":"お、おい……","ENG":"W-what...?","TWN":"啊？啊啊……？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"잠깐만… 너희들은……?","JPN":"あんたたち……まさか……？","ENG":"Hold on... who are you people...?","TWN":"等一下…你們是……？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ROSE_BETA_MAID_ON","text":{"KOREA":"……수신.","JPN":"……了解。","ENG":"...Copy that.","TWN":"……收到。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_ON","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L12_1","type":"dialog","speaker":"ROSE_BETA_MAID_ON","text":{"KOREA":"그럼, 다음 작전 페이즈를 이행하겠습니다.","JPN":"それでは、次の作戦フェーズに移行します。","ENG":"Proceeding to the next phase of the operation.","TWN":"那麼，接下來進入下一個作戰階段。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"야, 꼬맹이. 튈 준비해.","JPN":"おい、おこちゃま。逃げるぞ。","ENG":"Hey, kid. Get ready to run.","TWN":"喂，小不點。準備逃跑吧。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"왜요? 라이카가 아는 사람들이에요?","JPN":"なによ？　知ってる人？","ENG":"Huh? Do you know them, Laika?","TWN":"為什麼？是萊卡認識的人嗎？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"모를 리가 없지. 저 고약한 취향의 메이드복…….","JPN":"知ってるとも。あの悪趣味なメイド服……","ENG":"Of course I do. That awful taste in maid outfits... hard to forget.","TWN":"怎麼可能不知道呢。那惡趣味的女僕裝……"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ROSE_BETA_MAID_ON","text":{"KOREA":"안심하세요, 여러분. 여러분들은 곧 납치될 테니까요.","JPN":"ご安心ください、皆さん。貴方たちは今から拉致されますので。","ENG":"Don't worry, everyone. You're about to be kidnapped.","TWN":"放心吧，各位。你們很快就會被綁架的。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"……납치라고요?","JPN":"……拉致？","ENG":"...Kidnapped?","TWN":"……挾持？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L24_1","type":"dialog","speaker":"ROSE_BETA_MAID_ON","text":{"KOREA":"네. 마스터께서는 여러분들을 조용하고, 정중하게 모시라고 하셨습니다.","JPN":"はい。マスターは皆さんを静かに、丁寧に連れてくるようにとおっしゃいました。","ENG":"Yes. Master instructed us to escort you quietly and respectfully.","TWN":"是。主人吩咐我安靜而恭敬地接待各位。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_ON","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROSE_BETA_MAID_ON","text":{"KOREA":"그러니까 되도록 조용하고, 정중하게 납치해 드리겠습니다.","JPN":"ですからなるべく静かで丁寧に拉致して差し上げます。","ENG":"So we'll be kidnapping you as quietly and respectfully as possible.","TWN":"所以我會儘量安靜且禮貌地綁架你。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"싫다면……?","JPN":"嫌だと言ったら……？","ENG":"And if we say no...?","TWN":"如果不願意的話……"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L30_1","type":"dialog","speaker":"ROSE_BETA_MAID_ON","text":{"KOREA":"아쉽게도 여러분에게 거부권은 없습니다. 마스터의 명령은 절대적이니까요.","JPN":"残念ながら皆さんに拒否権はありません。マスターの命は絶対的ですので。","ENG":"Unfortunately, refusal isn't an option. Master's orders are absolute.","TWN":"可惜你們沒有拒絕的權利。主人的命令是絕對的。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_ON","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ROSE_BETA_MAID_ON","text":{"KOREA":"그러니까 우선 조용하게 만들어 드리죠.","JPN":"ですから、まずは静かにさせてあげましょう。","ENG":"So let's start by making you quiet.","TWN":"所以我先讓你們安靜一下吧。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_ON","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L33_1","type":"dialog","speaker":"ROSE_BETA_MAID_ON","text":{"KOREA":"정중히 모시는 건, 그 다음입니다.","JPN":"丁寧に連れて行くのはその後です。","ENG":"We'll be respectful after that.","TWN":"恭敬地侍奉，是在那之後的事。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_ON","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};